const PI: Real = 3.14159265;

@pure
fn area(radius: Real) -> Real {
    ret PI * radius * radius;
}

fn main() -> Void {
    let a: Real = area(2.5);
    fx {
        println("area=", a:0:2);
    }
    ret;
}

