@pure
fn admit(age: Int, hasTicket: Bool, isVip: Bool, flagged: Bool) -> Bool {
    ret age >= 18 && (hasTicket || isVip) && !flagged;
}

fn main() -> Void {
    fx {
        println("guest 0: ", admit(20, true, false, false));
        println("guest 1: ", admit(16, true, false, false));
        println("guest 2: ", admit(25, false, false, false));
        println("guest 3: ", admit(30, false, true, true));
        println("guest 4: ", admit(40, true, false, false));
    }
    ret;
}

@pure
fn validName(name: Text) -> Bool {
    let n: Int = string_len(name);
    if n < 1 {
        ret false;
    }
    if n > 6 {
        ret false;
    }
    if name == "bad" {
        ret false;
    }
    ret true;
}

fn main() -> Void {
    fx {
        println("alpha=", validName("alpha"));
        println("empty=", validName(""));
        println("bad=", validName("bad"));
    }
    ret;
}

type Point {
    x: Int;
    y: Int;
}

type Box {
    width: Int;
    height: Int;
}

fn shiftX(self: Point, dx: Int) -> Int {
    ret self.x + dx;
}

fn area(self: Box) -> Int {
    ret self.width * self.height;
}

fn main() -> Void {
    let p: Point = Point { x: 3, y: 4 };
    let b: Box = Box { width: 5, height: 6 };
    fx {
        println("shiftedX=", p.shiftX(10));
        println("area=", b.area());
        println("combined=", p.shiftX(10) + b.area());
    }
    ret;
}

@post result.0 >= result.1
fn ordered(a: Int, b: Int) -> (Int, Int) {
    if a >= b {
        ret (a, b);
    }
    ret (b, a);
}

fn main() -> Void {
    let (hi, lo) = ordered(3, 8);
    fx {
        println("hi=", hi);
        println("lo=", lo);
    }
    ret;
}

fn main() -> Void {
    let readings: Int[] = [12, 5, 23, 8, 19];
    let lo: Int = readings[0];
    let hi: Int = readings[0];
    loop i in 0..length(readings) {
        let v: Int = readings[i];
        if v < lo {
            lo = v;
        }
        if v > hi {
            hi = v;
        }
    }
    fx {
        println("min = ", lo);
        println("max = ", hi);
        println("range = ", hi - lo);
    }
    ret;
}

@pre score >= 0
@post result <= 100
fn normalize(score: Int) -> Int {
    if score > 100 {
        ret 100;
    }
    ret score;
}

fn main() -> Void {
    fx {
        println("150 => ", normalize(150));
        println("42 => ", normalize(42));
    }
    ret;
}

