    let teams: ToonNode = toon_key(root, "teams");
    let grand: Int = 0;
    loop i in 0..toon_len(teams) {
        let team: ToonNode = toon_at(teams, i);
        let name: Text = toon_get_text_or(team, "name", "UNKNOWN");
